fn:batch_decode(sequences)->dict[str,any] = {
  char_preds,bpe_preds,wp_preds = sequences,
  batch_size = char_preds.size(0),
  char_strs,scores = _decode_helper(char_preds,"char"),
  bpe_strs,bpe_scores = _decode_helper(bpe_preds,"bpe"),
  wp_strs,wp_scores = _decode_helper(wp_preds,"wp"),
  final_strs,final_scores = [max([char_scores[i],bpe_scores[i],wp_scores[i]],key=max)[strs[i] for strs in zip(char_strs,bpe_strs,wp_strs)] for i in range(batch_size)],
  **{k:v for k,v in zip("generated_text,scores,char_preds,bpe_preds,wp_preds",[final_strs,final_scores,char_strs,bpe_strs,wp_strs])}
}
